css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #14070a; color: white; overflow-x: hidden; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; }
.brand { font-size: 20px; font-weight: 800; }
.nav-links { display: flex; gap: 32px; }
.nav-links a { color: rgba(255,255,255,0.65); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-btn { background: linear-gradient(135deg, #ef4444, #f87171); border: none; color: white; padding: 11px 26px; border-radius: 999px; font-size: 13.5px; font-weight: 700; cursor: pointer; }
.hero { display: flex; align-items: center; justify-content: space-between; padding: 60px 60px 90px; gap: 60px; flex-wrap: wrap; }
.hero-text { max-width: 500px; }
.badge { display: inline-block; background: rgba(239,68,68,0.15); color: #f87171; font-size: 12.5px; font-weight: 700; padding: 6px 16px; border-radius: 999px; margin-bottom: 20px; }
.hero-text h1 { font-size: 52px; font-weight: 800; line-height: 1.2; margin-bottom: 18px; }
.hero-text h1 span { color: #f87171; }
.hero-text p { color: rgba(255,255,255,0.55); font-size: 16px; line-height: 1.7; margin-bottom: 28px; }
.hero-actions { display: flex; gap: 14px; flex-wrap: wrap; }
.btn-primary { background: linear-gradient(135deg, #ef4444, #f87171); border: none; color: white; padding: 15px 30px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; box-shadow: 0 12px 30px rgba(239,68,68,0.3); }
.btn-secondary { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.18); color: white; padding: 15px 30px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; }
.hero-visual { position: relative; width: 280px; height: 280px; flex-shrink: 0; display: flex; align-items: center; justify-content: center; }
.visual-circle { width: 220px; height: 220px; border-radius: 50%; background: radial-gradient(circle, rgba(239,68,68,0.2), transparent 70%); display: flex; align-items: center; justify-content: center; font-size: 90px; }
.float-card { position: absolute; background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.12); backdrop-filter: blur(10px); padding: 10px 16px; border-radius: 12px; font-size: 12.5px; font-weight: 700; }
.float-1 { top: 10px; right: -20px; }
.float-2 { bottom: 0; left: -40px; }
.impact { display: grid; grid-template-columns: repeat(4, 1fr); gap: 2px; padding: 40px 60px; background: rgba(239,68,68,0.06); }
.impact-stat { text-align: center; padding: 20px; display: flex; flex-direction: column; gap: 4px; }
.impact-stat strong { font-size: 28px; font-weight: 800; color: #f87171; }
.impact-stat span { font-size: 12.5px; color: rgba(255,255,255,0.5); }
.projects, .donate { padding: 70px 60px; }
.projects h2, .donate h2 { font-size: 32px; font-weight: 800; text-align: center; margin-bottom: 40px; }
.project-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 24px; max-width: 1100px; margin: 0 auto; }
.project-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 18px; padding: 24px; }
.project-img { font-size: 36px; margin-bottom: 14px; }
.project-card h3 { font-size: 17px; font-weight: 700; margin-bottom: 8px; }
.project-card p { color: rgba(255,255,255,0.5); font-size: 13px; line-height: 1.6; margin-bottom: 16px; }
.progress-bar { height: 8px; background: rgba(255,255,255,0.06); border-radius: 999px; overflow: hidden; margin-bottom: 14px; }
.progress-bar div { height: 100%; background: linear-gradient(90deg, #ef4444, #f87171); border-radius: 999px; }
.project-foot { display: flex; justify-content: space-between; align-items: center; }
.project-foot span { font-size: 12px; color: rgba(255,255,255,0.45); font-weight: 600; }
.project-foot button { background: rgba(239,68,68,0.12); border: none; color: #f87171; padding: 8px 16px; border-radius: 999px; font-size: 12px; font-weight: 700; cursor: pointer; }
.donate { text-align: center; background: linear-gradient(135deg, rgba(239,68,68,0.1), transparent); }
.donate p { color: rgba(255,255,255,0.5); font-size: 14px; margin: -24px 0 28px; }
.amount-buttons { display: flex; gap: 12px; justify-content: center; margin-bottom: 28px; flex-wrap: wrap; }
.amount-buttons button { background: rgba(255,255,255,0.05); border: 1.5px solid rgba(255,255,255,0.1); color: white; padding: 14px 26px; border-radius: 12px; font-size: 15px; font-weight: 700; cursor: pointer; }
.amount-buttons button.active { background: rgba(239,68,68,0.15); border-color: #ef4444; color: #f87171; }
.btn-primary.big { font-size: 16px; padding: 17px 36px; }
@media (max-width: 900px) { .hero, .projects, .donate { padding: 50px 24px; flex-direction: column; } .hero-text h1 { font-size: 38px; } .impact { grid-template-columns: repeat(2, 1fr); padding: 30px 24px; } }

