let currentAmount = 100;

function selectAmount(btn, amount) {
  document.querySelectorAll('.amount-buttons button').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  currentAmount = amount;
  document.getElementById('amountLabel').textContent = `₺${amount}`;
}

function confirmDonate() {
  alert(`₺${currentAmount} bağışınız için teşekkür ederiz!`);
}

function donate(projectName) {
  alert(`${projectName} projesine bağış yapılıyor...`);
}
